def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.4)
            if capacity > 10:
                priority += 150 * np.log1p(capacity) + 40 * np.cos(capacity / 2)
            else:
                priority -= 50 * np.sqrt(usage_ratio)
            for p in range(1, 6):
                priority += ((-1) ** p) * np.sin(usage_ratio * np.pi * p) * 20 / p
            if capacity % 3 < 0.7:
                priority += 25 * np.tan(capacity / 8)
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 3500 * delta**1.7 + 100 * (1 - delta)
            for q in range(1, 9):
                priority += np.cos(usage_ratio * np.pi * q**1.1) * 25 / q
            if int(capacity * 100) % 5 == 0:
                priority += 50 * np.sin(capacity)
        elif 2 < usage_ratio <= 3:
            priority += 2500 * (usage_ratio - 2) ** 2.2
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.6:
                    priority += power * 30 / r
                    if r % 3 == 0:
                        priority += 5 * r
                else:
                    priority += (1 - power) * 20 / (r + 2)
                    if r == 10 and usage_ratio > 2.5:
                        priority += 25
            if capacity % 2.3 < 0.5:
                priority += 35 * np.sin(capacity * 3)
        elif 1 < usage_ratio <= 2:
            priority += 1200 * (usage_ratio - 1) ** 3
            for s in range(1, 15):
                ratio_pow = usage_ratio ** s
                priority += (np.tanh(ratio_pow * np.pi / 4) - 0.3) * 15 / s
                if usage_ratio < 0.04 * s:
                    priority -= 10 * s
            if capacity < 0.5:
                priority += np.log1p(capacity * 20) * 40
            elif capacity < 2:
                priority += (capacity % 3) * 30
        elif 0.5 < usage_ratio <= 1:
            priority += 200 * (1 - usage_ratio)
            for x in range(1, 12):
                ratio_pow = usage_ratio ** x
                priority += (np.sin(ratio_pow * np.pi / 2) - 0.2) * 12 / x
                if usage_ratio < 0.03 * x:
                    priority -= 8 * x
            if capacity < 0.2:
                priority += np.sqrt(capacity) * 300
            elif capacity < 1:
                priority += np.log1p(capacity * 18) * 35
            else:
                priority += (capacity % 6) * 22
        else:
            priority += 400 * (1 - usage_ratio)**2
            for y in range(1, 18):
                ratio_pow = usage_ratio ** y
                priority += (np.cos(ratio_pow * np.pi / 4) - 0.25) * 14 / y
                if usage_ratio < 0.015 * y:
                    priority -= 12 * y
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 25) * 45
            else:
                priority += (capacity % 7) * 28
        if capacity < 0.07:
            priority += 80
            if usage_ratio > 0.75:
                priority += 90
            elif usage_ratio < 0.12:
                priority -= 50
                for r in range(1, 7):
                    priority -= r * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for s in range(1, 6):
                if int(capacity * 1200) % (s + 4) == 0:
                    priority += s * 6
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.18:
                priority -= 40
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 90
                for u in range(1, 5):
                    priority += u * 8
            else:
                priority += 30
        bonus_score = 0
        if int(capacity * 2500) % 19 == 0:
            bonus_score += 15
        if int(capacity * 900) % 23 == 0:
            bonus_score -= 12
        if int(capacity * 200) % 9 == 0:
            bonus_score += 14
        for k in range(1, 9):
            diff = abs(usage_ratio - k / 9)
            if diff < 0.02:
                bonus_score += 20 / k
            elif diff < 0.05:
                bonus_score += 10 / k
            else:
                bonus_score -= 4 / k
        for m in range(1, 8):
            mod_check = int(capacity * 1800) % (m + 8)
            if mod_check == 0:
                bonus_score += m * 5
            elif mod_check == 3:
                bonus_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1800) % (n + 5)
            if mod_check == 0:
                bonus_score += 10 * n
            elif mod_check == 3:
                bonus_score -= 6 * n
        priority += bonus_score
        if usage_ratio < 0.005:
            for s in range(1, 8):
                priority -= s * 10
        elif usage_ratio > 0.995:
            for t in range(1, 7):
                priority += t * 12
        if capacity > 2.0:
            if capacity % 1 < 0.05:
                priority += 45
            if (int(capacity * 2500) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for v in range(1, 6):
                if (int(capacity * 600) % (v + 8) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.2e4
        if abs(priority) > 1.2e4:
            priority = np.sign(priority) * 1.2e4
        priorities[i] = priority
    return priorities
